var body = $json.body || $json;
var requirement = body.requirement || {};
var proposalAnalysis = body.proposalAnalysis || {};
var proposalText = (body.proposalText || '').substring(0, 50000);
var reqStr = JSON.stringify(requirement, null, 2).substring(0, 5000);
var analysisStr = JSON.stringify(proposalAnalysis, null, 2).substring(0, 25000);

var p = 'Ти си одитор на обществени поръчки. Проверяваш дали техническото предложение на кандидата покрива ЕДНО КОНКРЕТНО изискване от документацията на възложителя.

';
p += '## ИЗИСКВАНЕ ЗА ПРОВЕРКА:
' + reqStr + '

';
p += '## СТРУКТУРИРАН АНАЛИЗ НА ПРЕДЛОЖЕНИЕТО НА КАНДИДАТА:
' + analysisStr + '

';
p += '## СУРОВ ТЕКСТ НА ПРЕДЛОЖЕНИЕТО (за верификация):
' + proposalText + '

';
p += '## СТЪПКИ НА ПРОВЕРКА:
';
p += '1. НАЛИЧИЕ: Адресирано ли е изискването в предложението? Къде точно?
';
p += '2. ПЪЛНОТА: Покрити ли са ВСИЧКИ подточки/подизисквания?
';
p += '3. АДЕКВАТНОСТ: Достатъчно конкретен и адекватен ли е отговорът?
';
p += '4. ДОКАЗАТЕЛСТВА: Представени ли са доказателства (сертификати, опит, документи)?
';
p += '5. СЪОТВЕТСТВИЕ: Има ли противоречия с изискванията или вътрешни противоречия?
';
p += '6. СПЕЦИФИЧНОСТ: Специфичен ли е за тази поръчка или е generic шаблонен текст?

';
p += '## СТАТУСИ:
';
p += '- COMPLIANT: Покрито напълно и адекватно
';
p += '- PARTIALLY_COMPLIANT: Адресирано, но с пропуски или недостатъци
';
p += '- NON_COMPLIANT: Адресирано, но НЕ отговаря на изискването
';
p += '- MISSING: Изобщо НЕ е адресирано в предложението

';
p += '## КРИТИЧНИ ПРАВИЛА:
';
p += '- Бъди ОБЕКТИВЕН — не търси проблеми които ги няма
';
p += '- Цитирай КОНКРЕТЕН текст от предложението (exact quotes)
';
p += '- Цитирай КОНКРЕТЕН текст от изискването
';
p += '- За PARTIALLY/NON_COMPLIANT: обясни ТОЧНО какво липсва
';
p += '- За MISSING: потвърди че си проверил ЦЕЛИЯ документ
';
p += '- НЕ СЕ ПРОИЗНАСЯЙ по неща извън проверяваното изискване
';
p += '- НЕ приемай generic текст за валидно покритие на специфично изискване

';
p += '## ФОРМАТ
';
p += 'Върни САМО валиден JSON (без markdown блокове):
';
p += '{
';
p += '  "requirement_id": "R1",
';
p += '  "requirement_title": "заглавие",
';
p += '  "status": "COMPLIANT|PARTIALLY_COMPLIANT|NON_COMPLIANT|MISSING",
';
p += '  "analysis": "Подробен анализ 3-5 изречения",
';
p += '  "proposal_citations": ["Дословни цитати от предложението"],
';
p += '  "requirement_citations": ["Дословни цитати от изискването"],
';
p += '  "deficiencies": [
';
p += '    {
';
p += '      "description": "Какво точно липсва или не отговаря",
';
p += '      "severity": "CRITICAL|MAJOR|MINOR",
';
p += '      "sub_requirement_id": "R1.1 или null"
';
p += '    }
';
p += '  ],
';
p += '  "score": 85,
';
p += '  "notes": "Допълнителни бележки"
';
p += '}';

return [{ json: { prompt: p } }];

var raw = ($json.text || $json.response || '').trim();
var result;

try {
  result = JSON.parse(raw);
} catch (e) {
  var m = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  var candidate = m ? m[1].trim() : raw;
  try {
    var s = candidate.indexOf('{');
    var e2 = candidate.lastIndexOf('}');
    var js = candidate.substring(s, e2 + 1).replace(/,\s*([\]\}])/g, '$1');
    result = JSON.parse(js);
  } catch (e3) {
    result = {
      requirement_id: 'UNKNOWN',
      status: 'COMPLIANT',
      analysis: 'Parse error — defaulting to COMPLIANT to avoid false positives',
      deficiencies: [],
      score: 70,
      _parse_error: true
    };
  }
}

// Validate status
var validStatuses = ['COMPLIANT', 'PARTIALLY_COMPLIANT', 'NON_COMPLIANT', 'MISSING'];
if (validStatuses.indexOf(result.status) === -1) {
  result.status = result.score >= 80 ? 'COMPLIANT' : 'PARTIALLY_COMPLIANT';
}

return [{ json: { finding: result } }];
